VALUES
  ('optician-moex-02709', 'optician', 'optician-moex-106-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '關於無法配戴一般眼鏡可建議使用隱形眼鏡的情形，下列敘述何者正確？①放射狀角膜切開近視手術後', '["在屈 光性的兩眼高度不等視（anisometropia），宜選用隱形眼鏡，減少兩眼不等像造成的不適", "在圓錐角膜 造成之高度散光合併高度軸性近視的患者可使用硬式隱形眼鏡來矯正一般眼鏡無法矯正的散光", "僅", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "21dccecf40fb", "answer_pdf_sha1": "332b43e00546", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 34, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02710', 'optician', 'optician-moex-106-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '配戴硬式轉換型雙焦隱形眼鏡（translating bifocal GP lens）時，當眨眼時出現過度旋轉（excessive lens rotation），應如何處理最正確？', '["增加下方稜鏡垂重（prism ballast）", "減少下方稜鏡垂重", "更換為較平的鏡片", "增加鏡片直徑"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "21dccecf40fb", "answer_pdf_sha1": "332b43e00546", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02711', 'optician', 'optician-moex-106-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '下列何種配戴者特性最不適合使用硬式非球面多焦點隱形眼鏡？', '["瞳孔大小6 mm", "下眼皮較鬆弛", "電腦工作使用者", "初期老花眼"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "21dccecf40fb", "answer_pdf_sha1": "332b43e00546", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02712', 'optician', 'optician-moex-106-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '關於隱形眼鏡部分單眼視覺法（partial monovision）矯正老花，下列敘述何者正確？', '["一眼看遠一眼看近的隱形眼鏡處方，必要時可選擇再加戴一副框架老花眼鏡來看小字", "只有高度散光（>3.00 D）的老花眼才能配戴", "雙眼用遠用度數處方的隱形眼鏡處方", "雙眼用近用度數的眼鏡處方"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "21dccecf40fb", "answer_pdf_sha1": "332b43e00546", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02713', 'optician', 'optician-moex-106-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '關於同步視覺雙焦隱形眼鏡（simultaneous vision bifocals）驗配，下列敘述何者正確？', '["雙眼用近用度數的隱形眼鏡處方", "一眼用遠用度數處方，一眼用近用度數處方", "當進行戴鏡驗光時應避免選擇自動驗光儀（auto-refractor），因不可精確測量度數。（其鏡片設計使光 線同時通過遠距屈光區及近距屈光區）", "只有高度散光（>3.00 D）的老花眼才能配戴"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "21dccecf40fb", "answer_pdf_sha1": "332b43e00546", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02714', 'optician', 'optician-moex-106-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '關於隱形眼鏡矯正散光或老花，下列敘述何者正確？', '["淚液鏡是隱形眼鏡矯正老花之重要元素", "軟式隱形眼鏡可透過淚液鏡之形成矯正散光", "硬式隱形眼鏡可透過淚液鏡之形成矯正老花", "淚液鏡是戴隱形眼鏡時於隱形眼鏡與角膜之間形成類似鏡片的淚膜"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "21dccecf40fb", "answer_pdf_sha1": "332b43e00546", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02715', 'optician', 'optician-moex-106-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '對於老花眼患者，使用單眼視覺法（monovision）驗配隱形眼鏡之原則，下列敘述何者錯誤？', '["主要眼建議保留原度數，看遠", "非主要眼建議降低度數，看近", "非主要眼也可配戴多焦點隱形眼鏡", "較適用於白內障的患者"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "21dccecf40fb", "answer_pdf_sha1": "332b43e00546", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
